def _load_mock_data() -> Dict[str, Any]:
    # Default source: the last captured real response from disk.
    # You can force using the inline JSON blob by setting MOCK_PREFER_INLINE_JSON=1.
    prefer_inline = os.getenv("MOCK_PREFER_INLINE_JSON", "0").strip().lower() in {
        "1",
        "true",
        "yes",
        "y",
    }
    if not prefer_inline:
        try:
            with open(DEFAULT_MOCK_FILE, "r", encoding="utf-8") as f:
                payload = json.load(f)
            if isinstance(payload, dict):
                return {"shared": payload}
        except Exception:
            pass

    # Fallback: in-file JSON blob.
    # If it contains trailing junk (common when pasting huge payloads), fall back
    # to parsing only the first JSON value.
    try:
        return json.loads(MOCK_DATA_JSON)
    except json.JSONDecodeError as exc:
        try:
            text = (MOCK_DATA_JSON or "").lstrip()
            parsed, end = json.JSONDecoder().raw_decode(text)
            if isinstance(parsed, dict):
                return parsed
        except Exception:
            pass

        raise RuntimeError(
            f"Invalid MOCK_DATA_JSON (and could not load {DEFAULT_MOCK_FILE}): {exc}"
        ) from exc


def _get_request_payload() -> Dict[str, Any]:
    # Match app.py behavior: prefer form; otherwise parse raw JSON.
    if request.form:
        return {k: request.form.get(k) for k in request.form.keys()}
    raw = request.get_data(as_text=True) or ""
    if not raw.strip():
        return {}
    try:
        parsed = json.loads(raw)
        return parsed if isinstance(parsed, dict) else {}
    except json.JSONDecodeError:
        return {}


def _parse_comparison_methods(payload: Dict[str, Any], default_methods: List[str]) -> List[str]:
    methods = payload.get("comparison_methods")
    if methods is None:
        # Frontend sometimes uses camelCase
        methods = payload.get("comparisonMethods")
    if methods is None:
        methods = default_methods

    # methods may arrive as JSON string (from form)
    if isinstance(methods, str):
        try:
            methods = json.loads(methods)
        except Exception:
            methods = default_methods

    if not isinstance(methods, list):
        methods = default_methods

    # Normalize to strings
    methods = [str(m) for m in methods]

    # Enforce allowlist for mock backend: selectable comparison methods.
    # Adda is always included (not a selectable comparison option).
    allowed = {"AutoFeat", "MADlib", "CAAFE", "Baseline", "PGML"}
    filtered = [m for m in methods if m in allowed]

    # Ensure Adda always included, matching app.py behavior
    return ["Adda", *filtered]


def _ensure_metric_lengths(data: Dict[str, Any], methods: List[str]) -> None:
    """Align metric/time arrays by method name, then pad missing values.

    This keeps values matched to the right method when the caller reorders or
    subsets comparison methods.
    """

    perf = data.get("performanceData") or {}
    time_data = data.get("timeData") or {}

    original_perf_methods = perf.get("methods") if isinstance(perf.get("methods"), list) else []
    original_time_methods = time_data.get("methods") if isinstance(time_data.get("methods"), list) else []

    def _to_float(x: Any, fill: float) -> float:
        return float(x) if isinstance(x, (int, float)) else fill

    def _rebuild(
        obj: Dict[str, Any],
        original_methods: List[str],
        key: str,
        fill: float = 0.0,
    ) -> None:
        arr = obj.get(key)
        if not isinstance(arr, list):
            arr = []

        mapping: Dict[str, float] = {}
        for m, v in zip(original_methods, arr):
            mapping[str(m)] = _to_float(v, fill)

        obj[key] = [mapping.get(m, fill) for m in methods]

    # Performance metrics
    for k in ("auc", "f1", "accuracy", "precision", "recall"):
        _rebuild(perf, [str(m) for m in original_perf_methods], k, fill=0.0)
    perf["methods"] = methods

    # Time metrics
    for k in ("totalTime", "trainingTime", "preprocessingTime", "featureGenerationTime", "evaluationTime"):
        _rebuild(time_data, [str(m) for m in original_time_methods], k, fill=0.0)
    time_data["methods"] = methods

    data["performanceData"] = perf
    data["timeData"] = time_data


def _build_response(kind: str) -> Dict[str, Any]:
    mock = _load_mock_data()

    # Both endpoints intentionally share the exact same payload.
    selected_key = kind if kind in mock else "shared"
    if selected_key not in mock:
        return {"status": "fail", "message": f"No mock payload for {kind} (and no shared payload)"}

    payload = _get_request_payload()

    base = copy.deepcopy(mock[selected_key])
    data = base.get("data") if isinstance(base.get("data"), dict) else None
    if not data:
        return base

    default_methods = (data.get("performanceData") or {}).get("methods") or ["Adda", "CAAFE", "MADlib"]
    methods = _parse_comparison_methods(payload, default_methods=list(default_methods))
    _ensure_metric_lengths(data, methods)

    # Small conveniences: reflect dataset/model in message if provided
    dataset = payload.get("dataset") or payload.get("task_name")
    ml_model = payload.get("ml_model_type") or payload.get("mlModel")
    if dataset or ml_model:
        base["message"] = base.get("message", "")
        base["message"] += " (mock)"
        if dataset:
            base["message"] += f" dataset={dataset}"
        if ml_model:
            base["message"] += f" ml_model_type={ml_model}"

    return base


app = Flask(__name__)
CORS(app, resources={r"/*": {"origins": "*"}}, supports_credentials=True)


@app.get("/health")
def health() -> Any:
    return jsonify({"status": "ok"})


@app.post("/auto-step/")
def auto_step() -> Any:
    return jsonify(_build_response("auto_step"))


# Compatibility alias: some callers use underscore naming
@app.post("/auto_step/")
def auto_step_alias() -> Any:
  return jsonify(_build_response("auto_step"))


@app.post("/performance-evaluation/")
def performance_evaluation() -> Any:
    return jsonify(_build_response("performance_evaluation"))


# Compatibility aliases: underscore naming or missing trailing slash
@app.post("/performance_evaluation/")
def performance_evaluation_alias() -> Any:
  return jsonify(_build_response("performance_evaluation"))


@app.post("/performance-evaluation")
def performance_evaluation_no_slash() -> Any:
  return jsonify(_build_response("performance_evaluation"))


if __name__ == "__main__":
    host = os.getenv("MOCK_HOST", "0.0.0.0")
    port = int(os.getenv("MOCK_PORT", "5000"))
    debug = os.getenv("MOCK_DEBUG", "0").strip().lower() in {"1", "true", "yes", "y"}
    app.run(host=host, port=port, debug=debug, use_reloader=debug)
